import React from "react"
import { graphql } from "gatsby"
import { MDXRenderer } from "gatsby-plugin-mdx"
import Layout from "../../components/Layout"

export default function PageTemplate({ pageContext: { language }, data: { mdx } }) {

	const title = mdx.frontmatter.header || mdx.frontmatter.title

	return (
		<Layout
			lang={language}
			mdx={mdx}
			title={title}
			collection={"pages"}
			showCover={true}
			customTitle={true}
			indexThis={!mdx.frontmatter.skipIndex}
		>
			<MDXRenderer>{mdx.body}</MDXRenderer>
		</Layout>
	)
}

export const pageQuery = graphql`
	query PageQuery($id: String) {
		mdx(id: { eq: $id }) {
			id
			body
			fields {
				slug
			}
			frontmatter {
				title
				header
				subtitle
				cover {
					publicURL
					childImageSharp {
						gatsbyImageData(layout: FULL_WIDTH)
						thumbnail: gatsbyImageData(layout: CONSTRAINED, width: 160, height: 160)
					}
				}
				skipIndex
			}
		}
	}
`